import React, { useState, useRef } from 'react';
import Header from './components/Header';
import ModelSelector from './components/ModelSelector';
import AnalyticsPanel from './components/AnalyticsPanel';
import { ModelType, FileData, OCRResult } from './types';
import { performOCR } from './services/geminiService';
import { UploadCloud, FileText, Loader2, Copy, Check, File as FileIcon, X } from 'lucide-react';

const App: React.FC = () => {
  const [selectedModel, setSelectedModel] = useState<ModelType>(ModelType.GEMINI_3_FLASH);
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<OCRResult | null>(null);
  const [editableText, setEditableText] = useState('');
  const [isCopied, setIsCopied] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setError(null);
    setResult(null);
    setEditableText('');

    // Limit to PDF and Images
    if (!file.type.startsWith('image/') && file.type !== 'application/pdf') {
      setError("Please upload a valid image or PDF document.");
      return;
    }

    try {
      // Read file as Base64
      const reader = new FileReader();
      reader.onload = (e) => {
        const result = e.target?.result as string;
        // Split to get pure base64
        const base64 = result.split(',')[1];
        setFileData({
          file,
          previewUrl: result, // data URL for preview
          base64,
          mimeType: file.type
        });
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setError("Failed to read file.");
      console.error(err);
    }
  };

  const handleOCR = async () => {
    if (!fileData) return;

    setIsProcessing(true);
    setError(null);

    try {
      const ocrResult = await performOCR(fileData.base64, fileData.mimeType, selectedModel);
      setResult(ocrResult);
      setEditableText(ocrResult.text);
    } catch (err: any) {
      setError(err.message || "An unexpected error occurred during OCR processing.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(editableText);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  const clearFile = () => {
    setFileData(null);
    setResult(null);
    setEditableText('');
    setError(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-slate-50">
      <Header />

      <main className="flex-grow max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-full">

          {/* Left Column: Input & Preview */}
          <div className="flex flex-col space-y-6">

            {/* Upload Area */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="p-6 border-b border-slate-100">
                <h2 className="text-lg font-semibold text-slate-800 flex items-center">
                  <UploadCloud className="h-5 w-5 mr-2 text-blue-600" />
                  Document Input
                </h2>
              </div>

              <div className="p-6">
                {!fileData ? (
                  <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="border-2 border-dashed border-slate-300 rounded-xl p-10 text-center cursor-pointer hover:bg-slate-50 hover:border-blue-400 transition-all group"
                  >
                    <input 
                      type="file" 
                      ref={fileInputRef} 
                      className="hidden" 
                      onChange={handleFileChange} 
                      accept="image/*,application/pdf"
                    />
                    <div className="bg-blue-100 p-4 rounded-full w-16 h-16 mx-auto mb-4 flex items-center justify-center group-hover:scale-110 transition-transform">
                      <FileText className="h-8 w-8 text-blue-600" />
                    </div>
                    <h3 className="text-slate-700 font-medium text-lg mb-2">Click to Upload Document</h3>
                    <p className="text-slate-500 text-sm">Support for Images (JPG, PNG) & PDF</p>
                    <p className="text-slate-400 text-xs mt-2">Optimized for Challans, Receipts, and Official Docs</p>
                  </div>
                ) : (
                  <div className="border border-slate-200 rounded-lg p-4 bg-slate-50">
                    <div className="flex items-center justify-between mb-4">
                      <div className="flex items-center space-x-3">
                        <div className="bg-red-100 p-2 rounded-lg">
                          <FileIcon className="h-5 w-5 text-red-600" />
                        </div>
                        <div className="overflow-hidden">
                          <p className="text-sm font-medium text-slate-900 truncate max-w-[200px]">{fileData.file.name}</p>
                          <p className="text-xs text-slate-500">{(fileData.file.size / 1024).toFixed(2)} KB</p>
                        </div>
                      </div>
                      <button 
                        onClick={clearFile}
                        className="p-1 hover:bg-slate-200 rounded-full text-slate-400 hover:text-slate-600 transition-colors"
                      >
                        <X className="h-5 w-5" />
                      </button>
                    </div>

                    <div className="relative aspect-[3/4] w-full bg-slate-200 rounded-lg overflow-hidden border border-slate-300">
                      {fileData.mimeType === 'application/pdf' ? (
                         <object 
                         data={fileData.previewUrl} 
                         type="application/pdf" 
                         className="w-full h-full"
                       >
                         <div className="flex items-center justify-center h-full text-slate-500">
                           <p>PDF Preview Not Available</p>
                         </div>
                       </object>
                      ) : (
                        <img 
                          src={fileData.previewUrl} 
                          alt="Document Preview" 
                          className="w-full h-full object-contain" 
                        />
                      )}
                    </div>
                  </div>
                )}
              </div>
            </div>

            {/* Processing Action (Desktop Sticky) */}
            {fileData && (
              <button
                onClick={handleOCR}
                disabled={isProcessing}
                className={`w-full py-4 rounded-xl shadow-lg flex items-center justify-center text-lg font-bold transition-all transform hover:-translate-y-1 ${
                  isProcessing 
                    ? 'bg-slate-800 cursor-not-allowed opacity-80' 
                    : 'bg-gradient-to-r from-blue-600 to-indigo-700 hover:from-blue-700 hover:to-indigo-800 text-white'
                }`}
              >
                {isProcessing ? (
                  <>
                    <Loader2 className="animate-spin mr-3 h-6 w-6" />
                    Extracting Text...
                  </>
                ) : (
                  <>
                    Run Sysnova OCR Engine
                  </>
                )}
              </button>
            )}

            {error && (
              <div className="bg-red-50 text-red-700 p-4 rounded-lg border border-red-200 text-sm">
                <strong>Error:</strong> {error}
              </div>
            )}
          </div>

          {/* Right Column: Settings & Result */}
          <div className="flex flex-col h-full">

            {/* Settings & Analytics */}
            <ModelSelector 
              selectedModel={selectedModel} 
              onModelChange={setSelectedModel} 
              disabled={isProcessing}
            />

            <AnalyticsPanel result={result} />

            {/* Output Editor */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 flex-grow flex flex-col overflow-hidden min-h-[500px]">
              <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-slate-50">
                <h2 className="text-lg font-semibold text-slate-800 flex items-center">
                  <FileText className="h-5 w-5 mr-2 text-green-600" />
                  Extracted Output
                </h2>
                {result && (
                  <button
                    onClick={handleCopy}
                    className="flex items-center space-x-1 px-3 py-1.5 bg-white border border-slate-300 rounded-md text-sm font-medium text-slate-700 hover:bg-slate-50 transition-colors"
                  >
                    {isCopied ? <Check className="h-4 w-4 text-green-600" /> : <Copy className="h-4 w-4 text-slate-500" />}
                    <span>{isCopied ? 'Copied' : 'Copy Text'}</span>
                  </button>
                )}
              </div>

              <div className="flex-grow relative bg-white">
                 {isProcessing ? (
                   <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/80 z-10 backdrop-blur-sm">
                     <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mb-4"></div>
                     <p className="text-slate-600 font-medium animate-pulse">Analyzing document structure...</p>
                     <p className="text-xs text-slate-400 mt-2">Processing Bangla & English layout</p>
                   </div>
                 ) : null}

                 <textarea
                  value={editableText}
                  onChange={(e) => setEditableText(e.target.value)}
                  placeholder={fileData ? "Extracted text will appear here..." : "Upload a document to begin..."}
                  className="w-full h-full p-6 resize-none focus:outline-none focus:ring-2 focus:ring-inset focus:ring-blue-500/50 bangla-text text-slate-800 font-mono text-sm leading-relaxed whitespace-pre-wrap"
                  spellCheck="false"
                 />
              </div>

              <div className="bg-slate-50 p-3 border-t border-slate-200 text-xs text-slate-500 flex justify-between">
                 <span>Editable Area</span>
                 <span>{editableText.length} characters</span>
              </div>
            </div>

          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

