import React, { useState } from 'react';
import { DeliveryChalanDocument, SubmitChalanRequest } from '../../types/delivery-chalan';
import { Check, Copy, Send, AlertTriangle, Loader2 } from 'lucide-react';

interface SubmitPanelProps {
  document: DeliveryChalanDocument;
  correctionCount: number;
}

const SubmitPanel: React.FC<SubmitPanelProps> = ({ document, correctionCount }) => {
  const [isCopied, setIsCopied] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const apiUrl = import.meta.env.VITE_CHALAN_API_URL;

  const handleCopy = () => {
    navigator.clipboard.writeText(JSON.stringify(document, null, 2));
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  const handleSubmit = async () => {
    if (!apiUrl) return;

    // Basic validation
    if (!document.chalan_number && !document.po_number) {
        alert("Please provide at least a Chalan Number or PO Number.");
        return;
    }

    setIsSubmitting(true);
    setSubmitStatus('idle');

    try {
      const payload: SubmitChalanRequest = {
        document,
        corrections_made: correctionCount > 0,
        correction_count: correctionCount
      };

      const response = await fetch(apiUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      if (!response.ok) throw new Error('Failed to submit');
      setSubmitStatus('success');
      setTimeout(() => setSubmitStatus('idle'), 3000);
    } catch (e) {
      console.error(e);
      setSubmitStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="bg-white border-t border-slate-200 p-4 flex items-center justify-between sticky bottom-0 z-10 shadow-lg">
      <div className="flex items-center space-x-4 text-sm text-slate-500">
        <span>{correctionCount} corrections made</span>
        {correctionCount > 0 && <span className="text-orange-500 flex items-center text-xs"><AlertTriangle className="h-3 w-3 mr-1" /> Edited</span>}
      </div>

      <div className="flex space-x-3">
        <button
          onClick={handleCopy}
          className={`flex items-center space-x-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
             isCopied 
             ? 'bg-green-100 text-green-800 border border-green-200' 
             : 'bg-white text-slate-700 border border-slate-300 hover:bg-slate-50'
          }`}
        >
          {isCopied ? <Check className="h-4 w-4" /> : <Copy className="h-4 w-4" />}
          <span>{isCopied ? 'JSON Copied' : 'Copy JSON'}</span>
        </button>

        <button
          onClick={handleSubmit}
          disabled={!apiUrl || isSubmitting}
          className={`flex items-center space-x-2 px-6 py-2 rounded-lg text-sm font-bold text-white transition-all ${
             !apiUrl 
               ? 'bg-slate-300 cursor-not-allowed' 
               : isSubmitting 
                 ? 'bg-blue-800 cursor-wait' 
                 : submitStatus === 'success'
                   ? 'bg-green-600'
                   : submitStatus === 'error'
                     ? 'bg-red-600'
                     : 'bg-blue-600 hover:bg-blue-700 shadow-md hover:shadow-lg'
          }`}
          title={!apiUrl ? "Configure VITE_CHALAN_API_URL to enable submission" : ""}
        >
            {isSubmitting ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  <span>Sending...</span>
                </>
            ) : submitStatus === 'success' ? (
                <>
                   <Check className="h-4 w-4" />
                   <span>Saved!</span>
                </>
            ) : submitStatus === 'error' ? (
                <span>Failed</span>
            ) : (
                <>
                    <Send className="h-4 w-4" />
                    <span>Submit Data</span>
                </>
            )}
        </button>
      </div>
    </div>
  );
};

export default SubmitPanel;

