import React from 'react';
import { DeliveryChalanDocument, ColumnDefinition, LineItemRow } from '../../types/delivery-chalan';
import ConfidenceBadge from './ConfidenceBadge';
import { Plus, Trash2, X } from 'lucide-react';

interface LineItemsTableProps {
  document: DeliveryChalanDocument;
  onUpdate: (updates: Partial<DeliveryChalanDocument>) => void;
}

const LineItemsTable: React.FC<LineItemsTableProps> = ({ document, onUpdate }) => {
  const { columns, rows } = document.line_items;

  // --- Row Operations ---

  const updateCell = (rowId: string, colId: string, value: string) => {
    const newRows = rows.map(row => {
      if (row.id === rowId) {
        return {
          ...row,
          cells: { ...row.cells, [colId]: value }
        };
      }
      return row;
    });
    onUpdate({ line_items: { ...document.line_items, rows: newRows } });
  };

  const addRow = () => {
    const newRow: LineItemRow = {
      id: Math.random().toString(36).substr(2, 9),
      cells: {},
      confidence: 1.0
    };
    // Initialize empty cells for all columns
    columns.forEach(col => newRow.cells[col.id] = "");

    onUpdate({ line_items: { ...document.line_items, rows: [...rows, newRow] } });
  };

  const removeRow = (rowId: string) => {
    if (!window.confirm('Are you sure you want to delete this row?')) return;
    const newRows = rows.filter(r => r.id !== rowId);
    onUpdate({ line_items: { ...document.line_items, rows: newRows } });
  };

  // --- Column Operations ---

  const addColumn = () => {
    const label = prompt("Enter new column name:");
    if (!label) return;

    const id = label.toLowerCase().replace(/\s+/g, '_');
    const newCol: ColumnDefinition = { id, label, type: 'text' };

    // Add to columns list
    const newColumns = [...columns, newCol];

    // Add empty cell to all existing rows
    const newRows = rows.map(row => ({
      ...row,
      cells: { ...row.cells, [id]: "" }
    }));

    onUpdate({ line_items: { columns: newColumns, rows: newRows } });
  };

  const removeColumn = (colId: string) => {
    if (!window.confirm('Delete this column and all its data?')) return;

    const newColumns = columns.filter(c => c.id !== colId);
    const newRows = rows.map(row => {
      const newCells = { ...row.cells };
      delete newCells[colId];
      return { ...row, cells: newCells };
    });

    onUpdate({ line_items: { columns: newColumns, rows: newRows } });
  };

  return (
    <div className="bg-white rounded-lg border border-slate-200 shadow-sm mb-6 overflow-hidden">
      <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex justify-between items-center">
        <h3 className="text-sm font-semibold text-slate-700">Line Items</h3>
        <button 
          onClick={addColumn}
          className="text-xs text-blue-600 hover:text-blue-800 font-medium flex items-center"
        >
          <Plus className="h-3 w-3 mr-1" /> Add Column
        </button>
      </div>

      <div className="overflow-x-auto">
        <table className="min-w-full divide-y divide-slate-200">
          <thead className="bg-slate-50">
            <tr>
              <th scope="col" className="px-3 py-2 text-left text-xs font-medium text-slate-400 uppercase tracking-wider w-10">
                #
              </th>
              {columns.map(col => (
                <th key={col.id} scope="col" className="group px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase tracking-wider border-r border-slate-100 last:border-0 relative min-w-[100px]">
                  <div className="flex items-center justify-between">
                    <input 
                       className="bg-transparent border-none p-0 text-xs font-bold uppercase tracking-wider focus:ring-0 w-full bangla-text"
                       value={col.label}
                       onChange={(e) => {
                           const newCols = columns.map(c => c.id === col.id ? { ...c, label: e.target.value } : c);
                           onUpdate({ line_items: { ...document.line_items, columns: newCols } });
                       }}
                    />
                    <button onClick={() => removeColumn(col.id)} className="opacity-0 group-hover:opacity-100 text-slate-300 hover:text-red-500 ml-1">
                      <X className="h-3 w-3" />
                    </button>
                  </div>
                </th>
              ))}
              <th scope="col" className="px-3 py-2 w-10"></th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-slate-200">
            {rows.map((row, idx) => (
              <tr key={row.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-3 py-2 whitespace-nowrap text-xs text-slate-400 text-center">
                  {idx + 1}
                </td>
                {columns.map(col => (
                  <td key={col.id} className="px-3 py-2 whitespace-nowrap border-r border-slate-100 last:border-0">
                    <input
                      type="text"
                      className={`w-full text-sm bg-transparent border-none focus:ring-1 focus:ring-blue-500 rounded px-2 py-1 bangla-text ${
                          col.type === 'number' || col.type === 'currency' ? 'text-right font-mono' : ''
                      }`}
                      value={row.cells[col.id] || ''}
                      onChange={(e) => updateCell(row.id, col.id, e.target.value)}
                    />
                  </td>
                ))}
                <td className="px-3 py-2 whitespace-nowrap text-right text-sm font-medium">
                  <div className="flex items-center justify-end space-x-2">
                    <ConfidenceBadge confidence={row.confidence} />
                    <button 
                      type="button"
                      onClick={(e) => {
                        e.stopPropagation();
                        removeRow(row.id);
                      }} 
                      className="text-slate-300 hover:text-red-600 p-1"
                      title="Delete Row"
                    >
                      <Trash2 className="h-4 w-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
            {rows.length === 0 && (
                <tr>
                    <td colSpan={columns.length + 2} className="px-6 py-8 text-center text-slate-400 italic">
                        No line items extracted. Add a row manually.
                    </td>
                </tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="bg-slate-50 border-t border-slate-200 px-4 py-3">
        <button
          onClick={addRow}
          className="flex items-center text-sm font-medium text-blue-600 hover:text-blue-800 transition-colors"
        >
          <Plus className="h-4 w-4 mr-1" /> Add Item Row
        </button>
      </div>
    </div>
  );
};

export default LineItemsTable;

import React, { useState, useRef } from 'react';
import { UploadCloud, FileText, Loader2, Sparkles, FileInput } from 'lucide-react';
import { ModelType } from '../../types';
import ModelSelector from '../ModelSelector';
import { performOCR } from '../../services/geminiService';
import { structureDeliveryChalan } from '../../services/structureService';
import { DeliveryChalanDocument } from '../../types/delivery-chalan';
import ChalanEditor from './ChalanEditor';

const StructuredEditorTab: React.FC = () => {
  const [selectedModel, setSelectedModel] = useState<ModelType>(ModelType.GEMINI_3_FLASH);
  const [fileData, setFileData] = useState<{file: File, previewUrl: string, base64: string, mimeType: string} | null>(null);
  const [status, setStatus] = useState<'idle' | 'ocr' | 'structuring' | 'ready' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [structuredDoc, setStructuredDoc] = useState<DeliveryChalanDocument | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const getModelDisplayName = (model: string) => {
      if (model.includes('pro')) return '3.0 Pro';
      if (model.includes('flash') && model.includes('3')) return '3.0 Flash';
      return '2.5 Flash';
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setErrorMessage(null);
    setStatus('idle');
    setStructuredDoc(null);

    const reader = new FileReader();
    reader.onload = (e) => {
      const result = e.target?.result as string;
      setFileData({
        file,
        previewUrl: result,
        base64: result.split(',')[1],
        mimeType: file.type
      });
    };
    reader.readAsDataURL(file);
  };

  const processDocument = async () => {
    if (!fileData) return;
    setErrorMessage(null);

    try {
      // Step 1: OCR
      setStatus('ocr');
      const ocrResult = await performOCR(fileData.base64, fileData.mimeType, selectedModel);

      // Step 2: Structuring
      setStatus('structuring');
      const structuredResult = await structureDeliveryChalan(ocrResult.text, selectedModel);

      setStructuredDoc(structuredResult);
      setStatus('ready');

    } catch (err: any) {
      console.error(err);
      setErrorMessage(err.message || "An unexpected error occurred.");
      setStatus('error');
    }
  };

  if (status === 'ready' && structuredDoc && fileData) {
    return (
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
         <div className="mb-4 flex items-center justify-between">
            <h2 className="text-xl font-bold text-slate-800">Structured Editor</h2>
            <button 
                onClick={() => { setStatus('idle'); setStructuredDoc(null); setFileData(null); }}
                className="text-sm text-slate-500 hover:text-slate-800 underline"
            >
                Upload New Document
            </button>
         </div>
         <ChalanEditor initialDocument={structuredDoc} imageUrl={fileData.previewUrl} />
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto py-12">
       <div className="text-center mb-10">
          <h2 className="text-3xl font-bold text-slate-900 mb-2">Delivery Chalan Extractor</h2>
          <p className="text-slate-500">Upload a Chalan image to extract structured data (Bangla/English) into editable JSON.</p>
       </div>

       <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden">

          <div className="p-8 border-b border-slate-100 bg-slate-50/50">
             <ModelSelector selectedModel={selectedModel} onModelChange={setSelectedModel} disabled={status !== 'idle' && status !== 'error'} />
          </div>

          <div className="p-8">
            {!fileData ? (
               <div 
               onClick={() => fileInputRef.current?.click()}
               className="border-2 border-dashed border-slate-300 rounded-xl p-16 text-center cursor-pointer hover:bg-slate-50 hover:border-blue-400 transition-all group"
             >
               <input 
                 type="file" 
                 ref={fileInputRef} 
                 className="hidden" 
                 onChange={handleFileChange} 
                 accept="image/*,application/pdf"
               />
               <div className="bg-indigo-100 p-5 rounded-full w-20 h-20 mx-auto mb-6 flex items-center justify-center group-hover:scale-110 transition-transform">
                 <Sparkles className="h-10 w-10 text-indigo-600" />
               </div>
               <h3 className="text-slate-900 font-semibold text-xl mb-2">Upload Delivery Chalan</h3>
               <p className="text-slate-500">Supports JPG, PNG & PDF</p>
             </div>
            ) : (
                <div className="flex flex-col items-center">
                    <div className="relative w-64 h-80 bg-slate-100 rounded-lg overflow-hidden border border-slate-200 mb-6 shadow-md">
                        <img src={fileData.previewUrl} className="w-full h-full object-contain" alt="Preview" />
                    </div>

                    {status === 'idle' || status === 'error' ? (
                        <div className="w-full max-w-md space-y-4">
                            {status === 'error' && (
                                <div className="bg-red-50 text-red-700 p-3 rounded-lg text-sm text-center mb-4 border border-red-200">
                                    {errorMessage}
                                </div>
                            )}
                            <button
                                onClick={processDocument}
                                className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-bold shadow-lg transform hover:-translate-y-0.5 transition-all flex items-center justify-center"
                            >
                                <Sparkles className="mr-2 h-5 w-5" /> Process Chalan Structure
                            </button>
                             <button
                                onClick={() => setFileData(null)}
                                className="w-full py-2 text-slate-500 hover:text-slate-700 font-medium text-sm"
                            >
                                Remove File
                            </button>
                        </div>
                    ) : (
                        <div className="w-full max-w-md text-center">
                            <Loader2 className="h-10 w-10 text-indigo-600 animate-spin mx-auto mb-4" />
                            <h3 className="text-lg font-semibold text-slate-800 mb-1">
                                {status === 'ocr' ? 'Step 1/2: Extracting Text...' : 'Step 2/2: Structuring Data...'}
                            </h3>
                            <p className="text-sm text-slate-500">Using {getModelDisplayName(selectedModel)} AI model</p>

                            <div className="w-full bg-slate-200 rounded-full h-2 mt-6 overflow-hidden">
                                <div 
                                    className="bg-indigo-600 h-2 rounded-full transition-all duration-1000 ease-in-out" 
                                    style={{ width: status === 'ocr' ? '40%' : '85%' }}
                                ></div>
                            </div>
                        </div>
                    )}
                </div>
            )}
          </div>
       </div>
    </div>
  );
};

export default StructuredEditorTab;

import React, { useState, useRef } from 'react';
import Header from './components/Header';
import ModelSelector from './components/ModelSelector';
import AnalyticsPanel from './components/AnalyticsPanel';
import { ModelType, FileData, OCRResult } from './types';
import { performOCR } from './services/geminiService';
import { UploadCloud, FileText, Loader2, Copy, Check, File as FileIcon, X, Wand2, Scan, TableProperties } from 'lucide-react';
import StructuredEditorTab from './components/StructuredEditor/StructuredEditorTab';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'ocr' | 'structured'>('ocr');

  // --- V1 OCR State ---
  const [selectedModel, setSelectedModel] = useState<ModelType>(ModelType.GEMINI_3_FLASH);
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<OCRResult | null>(null);
  const [editableText, setEditableText] = useState('');
  const [isCopied, setIsCopied] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const getModelDisplayName = (model: string) => {
    if (model.includes('pro')) return '3.0 Pro';
    if (model.includes('flash') && model.includes('3')) return '3.0 Flash';
    return '2.5 Flash';
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setError(null);
    setResult(null);
    setEditableText('');

    if (!file.type.startsWith('image/') && file.type !== 'application/pdf') {
      setError("Please upload a valid image or PDF document.");
      return;
    }

    try {
      const reader = new FileReader();
      reader.onload = (e) => {
        const result = e.target?.result as string;
        const base64 = result.split(',')[1];
        setFileData({
          file,
          previewUrl: result,
          base64,
          mimeType: file.type
        });
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setError("Failed to read file.");
      console.error(err);
    }
  };

  const handleOCR = async () => {
    if (!fileData) return;
    setIsProcessing(true);
    setError(null);
    try {
      const ocrResult = await performOCR(fileData.base64, fileData.mimeType, selectedModel);
      setResult(ocrResult);
      setEditableText(ocrResult.text);
    } catch (err: any) {
      setError(err.message || "An unexpected error occurred during OCR processing.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(editableText);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  const clearFile = () => {
    setFileData(null);
    setResult(null);
    setEditableText('');
    setError(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-slate-50">
      <Header />

      {/* Tab Navigation */}
      <div className="bg-white border-b border-slate-200 sticky top-16 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex space-x-8">
                <button
                    onClick={() => setActiveTab('ocr')}
                    className={`flex items-center space-x-2 py-4 px-1 border-b-2 text-sm font-medium transition-colors ${
                        activeTab === 'ocr' 
                        ? 'border-blue-600 text-blue-600' 
                        : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
                    }`}
                >
                    <Scan className="h-4 w-4" />
                    <span>Raw OCR (V1)</span>
                </button>
                <button
                    onClick={() => setActiveTab('structured')}
                    className={`flex items-center space-x-2 py-4 px-1 border-b-2 text-sm font-medium transition-colors ${
                        activeTab === 'structured' 
                        ? 'border-indigo-600 text-indigo-600' 
                        : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
                    }`}
                >
                    <TableProperties className="h-4 w-4" />
                    <span>Structured Editor (Delivery Chalan)</span>
                    <span className="ml-1.5 bg-indigo-100 text-indigo-700 py-0.5 px-2 rounded-full text-xs font-bold">V2</span>
                </button>
            </div>
        </div>
      </div>

      <main className="flex-grow max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Render New Structured Tab */}
        {activeTab === 'structured' && <StructuredEditorTab />}

        {/* Render Existing V1 OCR Tab */}
        {activeTab === 'ocr' && (
        <div className="flex flex-col gap-8 animate-in fade-in duration-300">

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

            <div className="flex flex-col space-y-6">
               <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden h-full">
                <div className="p-4 border-b border-slate-100 bg-slate-50">
                  <h2 className="text-lg font-semibold text-slate-800 flex items-center">
                    <UploadCloud className="h-5 w-5 mr-2 text-blue-600" />
