                  onClick={handleOCR}
                  disabled={isProcessing || !fileData}
                  className={`w-full py-4 rounded-xl shadow-md flex items-center justify-center text-lg font-bold transition-all transform hover:-translate-y-1 ${
                    !fileData
                      ? 'bg-slate-200 text-slate-400 cursor-not-allowed'
                      : isProcessing 
                        ? 'bg-slate-800 text-white cursor-not-allowed opacity-90' 
                        : 'bg-gradient-to-r from-blue-600 to-indigo-700 hover:from-blue-700 hover:to-indigo-800 text-white'
                  }`}
                >
                  {isProcessing ? (
                    <>
                      <Loader2 className="animate-spin mr-3 h-6 w-6" />
                      Processing Document...
                    </>
                  ) : (
                    <>
                      <Wand2 className="mr-2 h-5 w-5" />
                      Run Sysnova OCR
                    </>
                  )}
                </button>
                {!fileData && (
                   <p className="text-center text-xs text-slate-400 mt-2">Upload a document to enable processing</p>
                )}
              </div>
            </div>
          </div>

          <div className="w-full">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col overflow-hidden min-h-[600px] transition-all">
              <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/80 backdrop-blur">
                <div className="flex items-center space-x-2">
                  <div className="bg-green-100 p-1.5 rounded-md">
                    <FileText className="h-5 w-5 text-green-700" />
                  </div>
                  <div>
                    <h2 className="text-lg font-semibold text-slate-800">Extracted Output</h2>
                    <p className="text-xs text-slate-500">Editable • Formatted • {getModelDisplayName(selectedModel)}</p>
                  </div>
                </div>
                {result && (
                  <button
                    onClick={handleCopy}
                    className={`flex items-center space-x-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                        isCopied 
                        ? 'bg-green-100 text-green-800 border border-green-200' 
                        : 'bg-white text-slate-700 border border-slate-200 hover:bg-slate-50 hover:border-slate-300'
                    }`}
                  >
                    {isCopied ? <Check className="h-4 w-4" /> : <Copy className="h-4 w-4" />}
                    <span>{isCopied ? 'Copied to Clipboard' : 'Copy Text'}</span>
                  </button>
                )}
              </div>

              <div className="flex-grow relative bg-white">
                 {isProcessing && (
                   <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/90 z-20 backdrop-blur-[2px]">
                     <div className="animate-spin rounded-full h-12 w-12 border-4 border-slate-200 border-t-blue-600 mb-6"></div>
                     <p className="text-slate-800 font-semibold text-lg animate-pulse">Extracting Text & Layout...</p>
                     <p className="text-slate-500 mt-2">Please wait while our AI processes your document</p>
                   </div>
                 )}

                 <div className="relative w-full h-full">
                    {!editableText && !isProcessing && (
                        <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300 pointer-events-none p-8 text-center">
                            <FileText className="h-16 w-16 mb-4 opacity-20" />
                            <p className="text-xl font-medium opacity-40">Output will appear here</p>
                            <p className="text-sm opacity-40 mt-2 max-w-md">
                                The extracted text will preserve the original layout, spacing, and language of your uploaded document.
                            </p>
                        </div>
                    )}
                    <textarea
                        value={editableText}
                        onChange={(e) => setEditableText(e.target.value)}
                        placeholder=""
                        className="w-full h-full p-8 resize-none focus:outline-none focus:ring-0 bangla-text text-slate-800 font-mono text-base leading-7 whitespace-pre-wrap border-none"
                        spellCheck="false"
                        style={{ minHeight: '600px' }}
                    />
                 </div>
              </div>

              <div className="bg-slate-50 p-3 border-t border-slate-200 text-xs text-slate-500 flex justify-between px-6">
                 <span>Sysnova OCR Engine Output</span>
                 <div className="flex space-x-4">
                     <span>{editableText.length} characters</span>
                     <span>{editableText.split(/\s+/).filter(w => w.length > 0).length} words</span>
                 </div>
              </div>
            </div>
          </div>

        </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { DeliveryChalanDocument, ColumnDefinition, LineItemRow } from '../../types/delivery-chalan';
import ConfidenceBadge from './ConfidenceBadge';
import { Plus, Trash2, X } from 'lucide-react';

interface LineItemsTableProps {
  document: DeliveryChalanDocument;
  onUpdate: (updates: Partial<DeliveryChalanDocument>) => void;
}

const LineItemsTable: React.FC<LineItemsTableProps> = ({ document, onUpdate }) => {
  const { columns, rows } = document.line_items;

  // --- Row Operations ---

  const updateCell = (rowId: string, colId: string, value: string) => {
    const newRows = rows.map(row => {
      if (row.id === rowId) {
        return {
          ...row,
          cells: { ...row.cells, [colId]: value }
        };
      }
      return row;
    });
    onUpdate({ line_items: { ...document.line_items, rows: newRows } });
  };

  const addRow = () => {
    const newRow: LineItemRow = {
      // Use timestamp to ensure unique IDs during rapid addition
      id: `row_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
      cells: {},
      confidence: 1.0
    };
    // Initialize empty cells for all columns
    columns.forEach(col => newRow.cells[col.id] = "");

    onUpdate({ line_items: { ...document.line_items, rows: [...rows, newRow] } });
  };

  const removeRow = (rowId: string) => {
    if (window.confirm('Delete this row?')) {
        const newRows = rows.filter(r => r.id !== rowId);
        onUpdate({ line_items: { ...document.line_items, rows: newRows } });
    }
  };

  // --- Column Operations ---

  const addColumn = () => {
    const label = prompt("Enter new column name:");
    if (!label) return;

    const id = label.toLowerCase().replace(/\s+/g, '_') + '_' + Math.random().toString(36).substr(2, 5);
    const newCol: ColumnDefinition = { id, label, type: 'text' };

    // Add to columns list
    const newColumns = [...columns, newCol];

    // Add empty cell to all existing rows
    const newRows = rows.map(row => ({
      ...row,
      cells: { ...row.cells, [id]: "" }
    }));

    onUpdate({ line_items: { columns: newColumns, rows: newRows } });
  };

  const removeColumn = (colId: string) => {
    if (!window.confirm('Delete this column and all its data?')) return;

    const newColumns = columns.filter(c => c.id !== colId);
    const newRows = rows.map(row => {
      const newCells = { ...row.cells };
      delete newCells[colId];
      return { ...row, cells: newCells };
    });

    onUpdate({ line_items: { columns: newColumns, rows: newRows } });
  };

  return (
    <div className="bg-white rounded-lg border border-slate-200 shadow-sm mb-6 overflow-hidden">
      <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex justify-between items-center">
        <h3 className="text-sm font-semibold text-slate-700">Line Items</h3>
        <button 
          onClick={addColumn}
          className="text-xs text-blue-600 hover:text-blue-800 font-medium flex items-center"
        >
          <Plus className="h-3 w-3 mr-1" /> Add Column
        </button>
      </div>

      <div className="overflow-x-auto pb-4">
        <table className="min-w-full divide-y divide-slate-200">
          <thead className="bg-slate-50">
            <tr>
              <th scope="col" className="px-3 py-2 text-left text-xs font-medium text-slate-400 uppercase tracking-wider w-10">
                #
              </th>
              {columns.map(col => (
                <th key={col.id} scope="col" className="group px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase tracking-wider border-r border-slate-100 last:border-0 relative min-w-[120px]">
                  <div className="flex items-center justify-between">
                    <input 
                       className="bg-transparent border-none p-0 text-xs font-bold uppercase tracking-wider focus:ring-0 w-full bangla-text"
                       value={col.label}
                       onChange={(e) => {
                           const newCols = columns.map(c => c.id === col.id ? { ...c, label: e.target.value } : c);
                           onUpdate({ line_items: { ...document.line_items, columns: newCols } });
                       }}
                    />
                    <button onClick={() => removeColumn(col.id)} className="opacity-0 group-hover:opacity-100 text-slate-300 hover:text-red-500 ml-1">
                      <X className="h-3 w-3" />
                    </button>
                  </div>
                </th>
              ))}
              <th scope="col" className="px-3 py-2 w-16 text-right">Action</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-slate-200">
            {rows.map((row, idx) => (
              <tr key={row.id} className="hover:bg-slate-50 transition-colors group">
                <td className="px-3 py-2 whitespace-nowrap text-xs text-slate-400 text-center">
                  {idx + 1}
                </td>
                {columns.map(col => (
                  <td key={col.id} className="px-3 py-2 whitespace-nowrap border-r border-slate-100 last:border-0">
                    <input
                      type="text"
                      className={`w-full text-sm bg-transparent border-none focus:ring-1 focus:ring-blue-500 rounded px-2 py-1 bangla-text ${
                          col.type === 'number' || col.type === 'currency' ? 'text-right font-mono' : ''
                      }`}
                      value={row.cells[col.id] || ''}
                      onChange={(e) => updateCell(row.id, col.id, e.target.value)}
                    />
                  </td>
                ))}
                <td className="px-3 py-2 whitespace-nowrap text-right text-sm font-medium">
                  <div className="flex items-center justify-end space-x-2">
                    {/* Only show confidence if it exists and is less than 1, to reduce clutter */}
                    {row.confidence < 0.9 && <ConfidenceBadge confidence={row.confidence} />}
                    <button 
                      type="button"
                      onClick={() => removeRow(row.id)} 
                      className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded transition-colors"
                      title="Delete Row"
                    >
                      <Trash2 className="h-4 w-4 pointer-events-none" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
            {rows.length === 0 && (
                <tr>
                    <td colSpan={columns.length + 2} className="px-6 py-8 text-center text-slate-400 italic">
                        No line items extracted. Add a row manually.
                    </td>
                </tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="bg-slate-50 border-t border-slate-200 px-4 py-3">
        <button
          onClick={addRow}
          className="flex items-center text-sm font-medium text-blue-600 hover:text-blue-800 transition-colors"
        >
          <Plus className="h-4 w-4 mr-1" /> Add Item Row
        </button>
      </div>
    </div>
  );
};

export default LineItemsTable;

